package com.trademaster.ims.mobile.support.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_support_tickets",indexes={@Index(name="idx_support_ticket_account",columnList="customer_account_id"),@Index(name="idx_support_ticket_number",columnList="ticket_number",unique=true)})
public class SupportTicket{public enum Category{ORDER,PAYMENT,DELIVERY,RETURN,PRODUCT,ACCOUNT,OTHER}public enum Priority{LOW,NORMAL,HIGH,URGENT}public enum Status{OPEN,IN_PROGRESS,WAITING_FOR_CUSTOMER,RESOLVED,CLOSED}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="ticket_number",nullable=false,unique=true,length=48)private String ticketNumber;@Column(name="customer_account_id",nullable=false)private Long accountId;@Column(nullable=false,length=160)private String subject;@Enumerated(EnumType.STRING)@Column(nullable=false,length=24)private Category category=Category.OTHER;@Enumerated(EnumType.STRING)@Column(nullable=false,length=24)private Priority priority=Priority.NORMAL;@Enumerated(EnumType.STRING)@Column(nullable=false,length=32)private Status status=Status.OPEN;@Column(name="related_order_number",length=60)private String relatedOrderNumber;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private Long version;@PrePersist void c(){createdAt=updatedAt=Instant.now();}@PreUpdate void u(){updatedAt=Instant.now();}
public Long getId(){return id;}public String getTicketNumber(){return ticketNumber;}public void setTicketNumber(String v){ticketNumber=v;}public Long getAccountId(){return accountId;}public void setAccountId(Long v){accountId=v;}public String getSubject(){return subject;}public void setSubject(String v){subject=v;}public Category getCategory(){return category;}public void setCategory(Category v){category=v;}public Priority getPriority(){return priority;}public void setPriority(Priority v){priority=v;}public Status getStatus(){return status;}public void setStatus(Status v){status=v;}public String getRelatedOrderNumber(){return relatedOrderNumber;}public void setRelatedOrderNumber(String v){relatedOrderNumber=v;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}public Long getVersion(){return version;}}